import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import Loader from '../../../components/shared/Loader';
import { productService } from '../../../services/productService';
import { categoryService } from '../../../services/categoryService';

const ProductList = () => {
  const navigate = useNavigate();
  const [products, setProducts] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);
  
  // Bulk Selection
  const [selectedIds, setSelectedIds] = useState([]);
  const [bulkActionType, setBulkActionType] = useState('');
  const [bulkData, setBulkData] = useState(''); // e.g., category ID for UPDATE_CATEGORY

  const fetchInitData = async () => {
    try {
      setLoading(true);
      const [prodRes, catRes] = await Promise.all([
        productService.getProducts({ limit: 1000 }),
        categoryService.getCategories()
      ]);
      setProducts(prodRes.data.products || []);
      setCategories(catRes.data || []);
      setSelectedIds([]);
    } catch (error) {
      console.error("Error fetching data", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchInitData();
  }, []);

  const handleDelete = async (id) => {
    if (window.confirm('Delete this product permanently?')) {
      try {
        await productService.deleteProduct(id);
        fetchInitData();
      } catch (error) {
        alert('Failed to delete product');
      }
    }
  };

  const handleDuplicate = async (id) => {
    if (window.confirm('Clone this product along with all its variants and images?')) {
      try {
         await productService.duplicateProduct(id);
         fetchInitData();
      } catch(error) {
         alert('Failed to duplicate product');
      }
    }
  };

  const toggleStatus = async (id, field, currentValue) => {
    try {
      await productService.updateProduct(id, { [field]: !currentValue });
      fetchInitData();
    } catch (error) {
      alert('Action failed');
    }
  };

  const handleSelectAll = (e) => {
    if (e.target.checked) {
      setSelectedIds(products.map(p => p._id));
    } else {
      setSelectedIds([]);
    }
  };

  const handleSelectOne = (id) => {
    if (selectedIds.includes(id)) {
      setSelectedIds(selectedIds.filter(itemId => itemId !== id));
    } else {
      setSelectedIds([...selectedIds, id]);
    }
  };

  const handleBulkSubmit = async () => {
    if (!bulkActionType) return alert('Select an action type');
    if (selectedIds.length === 0) return alert('Select at least one product');

    let payloadData = {};
    if (bulkActionType === 'UPDATE_CATEGORY') {
      if (!bulkData) return alert('Please select a target category for bulk update.');
      payloadData = { categoryId: bulkData };
    } else if (bulkActionType === 'MARK_FEATURED') {
      payloadData = { isFeatured: bulkData === 'true' };
    } else if (bulkActionType === 'ENABLE_DISABLE') {
      payloadData = { isActive: bulkData === 'true' };
    }

    if (window.confirm(`Execute ${bulkActionType} on ${selectedIds.length} products?`)) {
      try {
        setLoading(true);
        await productService.bulkAction({
          action: bulkActionType,
          productIds: selectedIds,
          data: payloadData
        });
        setBulkActionType('');
        setBulkData('');
        fetchInitData();
      } catch (err) {
        alert('Bulk action failed');
      } finally {
        setLoading(false);
      }
    }
  };

  return (
    <div>
      <div className="flex justify-between items-center mb-8">
        <h1 className="text-2xl font-serif text-black">Enterprise Product Registry</h1>
        <Link 
          to="/admin/products/add" 
          className="bg-black text-white px-6 py-2 text-sm font-medium tracking-wide hover:bg-gold transition-colors shadow-sm"
        >
          Add New Product
        </Link>
      </div>

      <div className="bg-white shadow-sm border border-gray-100 rounded overflow-hidden">
        
        {/* Bulk Action Toolbar */}
        <div className="p-4 border-b border-gray-100 bg-gray-50 flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-4 w-full md:w-auto">
            <span className="text-sm font-medium text-gray-700">{selectedIds.length} Selected</span>
            
            <select 
              value={bulkActionType} 
              onChange={(e) => { setBulkActionType(e.target.value); setBulkData(''); }} 
              className="border border-gray-300 p-2 text-sm focus:outline-none focus:border-black bg-white disabled:opacity-50"
              disabled={selectedIds.length === 0}
            >
              <option value="">-- Bulk Actions --</option>
              <option value="DELETE">Delete Selected</option>
              <option value="UPDATE_CATEGORY">Change Category</option>
              <option value="MARK_FEATURED">Mark Featured Status</option>
              <option value="ENABLE_DISABLE">Enable / Disable</option>
            </select>

            {/* Dynamic Bulk Data Appender */}
            {bulkActionType === 'UPDATE_CATEGORY' && (
              <select value={bulkData} onChange={(e) => setBulkData(e.target.value)} className="border border-gray-300 p-2 text-sm focus:outline-none bg-white">
                 <option value="">Select Category</option>
                 {categories.map(c => <option key={c._id} value={c._id}>{c.name?.en}</option>)}
              </select>
            )}
            {bulkActionType === 'MARK_FEATURED' && (
              <select value={bulkData} onChange={(e) => setBulkData(e.target.value)} className="border border-gray-300 p-2 text-sm focus:outline-none bg-white">
                 <option value="">Select Status</option>
                 <option value="true">Feature (On)</option>
                 <option value="false">Un-feature (Off)</option>
              </select>
            )}
            {bulkActionType === 'ENABLE_DISABLE' && (
              <select value={bulkData} onChange={(e) => setBulkData(e.target.value)} className="border border-gray-300 p-2 text-sm focus:outline-none bg-white">
                 <option value="">Select Status</option>
                 <option value="true">Enable (Active)</option>
                 <option value="false">Disable (Hidden)</option>
              </select>
            )}

            {bulkActionType && (
              <button onClick={handleBulkSubmit} className="bg-black text-white px-4 py-1.5 text-xs uppercase font-bold tracking-wider hover:bg-gold transition-colors">Apply</button>
            )}
          </div>
          
          <input 
            type="text" 
            placeholder="Search products by SKU / Name..." 
            className="w-full sm:w-64 border border-gray-300 p-2 text-sm focus:outline-none focus:border-black"
          />
        </div>

        {/* Data Table */}
        <div className="overflow-x-auto">
          {loading ? (
            <Loader />
          ) : (
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-white border-b border-gray-100 text-xs uppercase tracking-wider text-gray-500">
                  <th className="px-4 py-4 w-10 text-center">
                    <input type="checkbox" onChange={handleSelectAll} checked={products.length > 0 && selectedIds.length === products.length} className="w-4 h-4 accent-black" />
                  </th>
                  <th className="px-4 py-4 font-medium">Image</th>
                  <th className="px-6 py-4 font-medium">Product Details</th>
                  <th className="px-6 py-4 font-medium">Category</th>
                  <th className="px-6 py-4 font-medium">Price</th>
                  <th className="px-6 py-4 font-medium">Variants / Stock</th>
                  <th className="px-6 py-4 font-medium">Status</th>
                  <th className="px-6 py-4 font-medium text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {products.length > 0 ? products.map((product) => {
                  const name = product.name?.en || product.name?.ar || product.name || 'Unknown';
                  const categoryName = product.category?.name?.en || product.category?.name?.ar || product.category?.name || 'Uncategorized';
                  const mainImageObj = product.images?.find(img => img.isMain) || product.images?.[0];
                  // If images is array of objects, take .url, else legacy string
                  const imageSrc = mainImageObj ? (mainImageObj.url || mainImageObj) : 'https://via.placeholder.com/100';
                  
                  return (
                    <tr key={product._id} className="hover:bg-gray-50 transition-colors">
                      <td className="px-4 py-4 text-center">
                        <input type="checkbox" checked={selectedIds.includes(product._id)} onChange={() => handleSelectOne(product._id)} className="w-4 h-4 accent-black" />
                      </td>
                      <td className="px-4 py-4">
                        <div className="w-12 h-12 bg-gray-200 rounded overflow-hidden border border-gray-100">
                          <img src={imageSrc} alt={name} className="w-full h-full object-cover" />
                        </div>
                      </td>
                      <td className="px-6 py-4 text-sm font-medium text-black">
                        <div className="flex items-center gap-2 mb-1">
                          {name}
                          {product.badges?.map(b => (
                            <span key={b} className="inline-flex items-center px-1.5 py-0.5 rounded text-[10px] font-bold bg-gray-800 text-white">{b}</span>
                          ))}
                        </div>
                        <div className="text-xs text-gray-500 font-mono tracking-tight">{product.sku}</div>
                      </td>
                      <td className="px-6 py-4 text-sm text-gray-600">{categoryName}</td>
                      <td className="px-6 py-4 text-sm font-medium text-black">
                        ${product.salePrice ? product.salePrice : product.price}
                        {product.salePrice && <span className="block text-xs line-through text-gray-400 font-normal">${product.price}</span>}
                      </td>
                      <td className="px-6 py-4 text-sm text-gray-600">
                        {product.variants?.length > 0 ? (
                           <span className="font-semibold text-blue-600 border-b border-blue-200 cursor-pointer">{product.variants.length} Variants</span>
                        ) : (
                           <span className={`font-bold ${product.stockControl?.totalStock < 5 ? 'text-red-600' : 'text-green-600'}`}>
                             {product.stockControl?.totalStock || product.stock || 0}
                           </span>
                        )}
                      </td>
                      <td className="px-6 py-4 text-sm space-y-1">
                        <div>
                          <button onClick={() => toggleStatus(product._id, 'isActive', product.isActive)} className={`text-xs px-2 py-1 rounded-full ${product.isActive ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                            {product.isActive ? 'Active' : 'Hidden'}
                          </button>
                        </div>
                        <div>
                           <button onClick={() => toggleStatus(product._id, 'isFeatured', product.isFeatured)} className={`text-xs px-2 py-1 rounded-full ${product.isFeatured ? 'bg-yellow-100 text-yellow-700' : 'bg-gray-100 text-gray-600'}`}>
                            {product.isFeatured ? '★ Featured' : 'Not Featured'}
                          </button>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-sm text-right space-x-3">
                        <button onClick={() => handleDuplicate(product._id)} className="text-emerald-600 hover:text-emerald-900 font-medium">Duplicate</button>
                        <Link to={`/admin/products/edit/${product._id}`} className="text-indigo-600 hover:text-indigo-900 font-medium">Edit</Link>
                        <button onClick={() => handleDelete(product._id)} className="text-red-600 hover:text-red-900 font-medium">Delete</button>
                      </td>
                    </tr>
                  )
                }) : (
                  <tr>
                    <td colSpan="8" className="text-center py-6 text-gray-500">No Enterprise products found. Add some!</td>
                  </tr>
                )}
              </tbody>
            </table>
          )}
        </div>

      </div>
    </div>
  );
};

export default ProductList;

